<template>
  <div class="chat-box border rounded-3 p-3 h-100 d-flex flex-column" style="height: 600px !important;">
    <!-- 对话内容区域 -->
    <div class="chat-content flex-grow-1 overflow-auto mb-3" id="chatContent">
      <!-- 机器人欢迎语 -->
      <div class="d-flex mb-3 justify-content-start">
        <div class="bg-light rounded-3 p-3 shadow-sm max-w-75">
          你好～我是校园生活小管家，有什么可以帮你的？<br>
          试试问我：<span class="text-primary">今日课表</span>、<span class="text-primary">食堂吃什么</span>、<span class="text-primary">报修电话是多少</span>、<span class="text-primary">下课后提醒我取快递</span>
        </div>
      </div>
      <!-- 对话消息列表 -->
      <div v-for="(msg, index) in msgList" :key="index" class="d-flex mb-3" :class="msg.isUser ? 'justify-content-end' : 'justify-content-start'">
        <div :class="msg.isUser ? 'bg-primary text-white rounded-3 p-3 shadow-sm max-w-75' : 'bg-light rounded-3 p-3 shadow-sm max-w-75'">
          {{ msg.content }}
          <!-- 结果卡片：课表/提醒/知识库 -->
          <ResultCard v-if="msg.data" :data="msg.data" :intent="msg.intent" />
        </div>
      </div>
    </div>
    <!-- 输入框区域 -->
    <div class="input-group">
      <input v-model="inputContent" type="text" class="form-control" placeholder="请输入你的问题..." @keyup.enter="sendMsg">
      <button class="btn btn-primary" type="button" @click="sendMsg">发送</button>
    </div>
  </div>
</template>

<script>
import ResultCard from './ResultCard.vue'
export default {
  name: 'ChatBox',
  components: { ResultCard },
  data() {
    return {
      inputContent: '', // 输入内容
      msgList: [], // 消息列表
      userId: 1 // 测试用户ID，可扩展为登录后获取
    }
  },
  mounted() {
    // 存储测试用户ID到Cookies
    this.$cookies.set('userId', this.userId, '7d')
  },
  methods: {
    // 发送消息
    async sendMsg() {
      if (!this.inputContent.trim()) {
        this.$message && this.$message.warning('请输入内容！')
        return
      }
      // 1. 添加用户消息到列表
      this.msgList.push({
        isUser: true,
        content: this.inputContent.trim()
      })
      const content = this.inputContent.trim()
      this.inputContent = ''
      // 2. 滚动到底部
      this.$nextTick(() => {
        const chatContent = document.getElementById('chatContent')
        chatContent.scrollTop = chatContent.scrollHeight
      })
      // 3. 调用后端接口
      try {
        const res = await this.$axios.post('/agent/chat', null, {
          params: {
            content: content,
            userId: this.userId
          }
        })
        if (res.data.code === 200) {
          // 4. 添加机器人消息到列表
          this.msgList.push({
            isUser: false,
            content: res.data.data.reply,
            data: res.data.data.data,
            intent: res.data.data.intent
          })
        } else {
          this.msgList.push({
            isUser: false,
            content: '服务出错了：' + res.data.msg
          })
        }
      } catch (err) {
        console.error(err)
        this.msgList.push({
          isUser: false,
          content: '网络出错了，请重试！'
        })
      } finally {
        // 5. 滚动到底部
        this.$nextTick(() => {
          const chatContent = document.getElementById('chatContent')
          chatContent.scrollTop = chatContent.scrollHeight
        })
      }
    }
  }
}
</script>

<style scoped>
.chat-box {
  background-color: #f8f9fa;
}
.chat-content {
  scroll-behavior: smooth;
}
</style>
